style_css = '/* ── Stats fade-in — no IntersectionObserver, fires on load ──────────────── */\n.stats-fade {\n  /* Default: visible immediately — no animation dependency */\n  opacity: 1;\n}\n/* Only animate if user hasn\'t requested reduced motion */\n@media (prefers-reduced-motion: no-preference) {\n  .stats-fade {\n    animation: statsFadeIn 500ms ease forwards;\n  }\n}\n@keyframes statsFadeIn {\n  from { opacity: 0; transform: translateY(10px); }\n  to   { opacity: 1; transform: none; }\n}\n\n/* ── Stats one-box ───────────────────────────────────────────────────────── */\n.stats-box {\n  display: flex;\n  flex-direction: row;\n  align-items: stretch;\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius);\n  margin: 2rem 0;\n  overflow: hidden;\n}\n.stat-item {\n  flex: 1;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  padding: 1.5rem .75rem;\n  text-align: center;\n  min-width: 0;\n}\n.stat-divider {\n  width: 1px;\n  background: var(--border);\n  flex-shrink: 0;\n  align-self: stretch;\n}\n.stat-value {\n  display: block;\n  font-size: 1.65rem;\n  font-weight: 700;\n  color: var(--accent);\n  line-height: 1;\n}\n.stat-label {\n  display: block;\n  font-size: .72rem;\n  color: var(--muted);\n  margin-top: .35rem;\n  line-height: 1.3;\n}\n@media (max-width: 640px) {\n  /* Mobile: stats wrap into 2 columns */\n  .stats-box { flex-wrap: wrap; }\n  .stat-item {\n    flex: 0 0 50%;\n    border-right: none;\n    border-bottom: 1px solid var(--border);\n    padding: 1rem .5rem;\n  }\n  .stat-item:nth-child(odd) { border-right: 1px solid var(--border); }\n  .stat-item:last-child { border-bottom: none; }\n  .stat-item:nth-last-child(2):nth-child(odd) { border-bottom: none; }\n  .stat-item:last-child:nth-child(odd) { flex: 0 0 100%; border-right: none; }\n  .stat-divider { display: none; }\n  .stat-value { font-size: 1.35rem; }\n  .stat-label { font-size: .68rem; }\n}\n\n/* Droidify — Pure CSS, no framework dependencies */\n\n/* ── Reset & base ──────────────────────────────────────────────────────────── */\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n:root {\n  --bg:       #0b0f14;\n  --card:     #121820;\n  --card2:    #18212c;\n  --border:   #1e2a3a;\n  --accent:   #3dd68c;\n  --accent2:  #2ab875;\n  --text:     #e8eef5;\n  --muted:    #8b9cb3;\n  --danger:   #f87171;\n  --warn:     #fbbf24;\n  --info:     #60a5fa;\n  --radius:   10px;\n  --radius-sm:6px;\n  --shadow:   0 2px 12px rgba(0,0,0,.4);\n  --transition: 180ms ease;\n}\n\nhtml { scroll-behavior: smooth; }\n\nbody {\n  font-family: system-ui, -apple-system, BlinkMacSystemFont, \'Segoe UI\', sans-serif;\n  background: var(--bg);\n  color: var(--text);\n  min-height: 100vh;\n  display: flex;\n  flex-direction: column;\n  line-height: 1.6;\n}\n\na { color: var(--accent); text-decoration: none; }\na:hover { text-decoration: underline; }\n\n/* ── Layout ────────────────────────────────────────────────────────────────── */\n.container {\n  max-width: 1140px;\n  margin: 0 auto;\n  padding: 0 1.25rem;\n}\n\nmain.container { flex: 1; padding-top: 2rem; padding-bottom: 4rem; }\n\n/* ── Header ────────────────────────────────────────────────────────────────── */\n.site-header {\n  position: sticky;\n  top: 0;\n  z-index: 100;\n  border-bottom: 1px solid var(--border);\n  background: rgba(18, 24, 32, 0.92);\n  backdrop-filter: blur(12px);\n}\n\n.header-inner {\n  display: flex;\n  align-items: center;\n  gap: 1rem;\n  height: 58px;\n}\n/* Logo always first, flex fills space after nav */\n.logo { flex-shrink: 0; }\n.nav-toggle { flex-shrink: 0; margin-left: .5rem; }\n\n.logo {\n  font-size: 1.25rem;\n  font-weight: 700;\n  letter-spacing: -.02em;\n  color: var(--text);\n}\n.logo:hover { text-decoration: none; }\n.accent { color: var(--accent); }\n\nnav { display: flex; gap: .25rem; flex-wrap: wrap; }\n\n.nav-link {\n  color: var(--muted);\n  font-size: .85rem;\n  padding: .35rem .65rem;\n  border-radius: var(--radius-sm);\n  transition: color var(--transition), background var(--transition);\n}\n.nav-link:hover,\n.nav-link.active {\n  color: var(--text);\n  background: var(--border);\n  text-decoration: none;\n}\n.nav-link.active { color: var(--accent); }\n\n/* ── Hero ──────────────────────────────────────────────────────────────────── */\n.hero { text-align: center; padding: 3.5rem 0 2rem; }\n.hero h1 {\n  font-size: clamp(1.8rem, 5vw, 3rem);\n  font-weight: 800;\n  letter-spacing: -.03em;\n  line-height: 1.15;\n}\n.hero-sub {\n  color: var(--muted);\n  max-width: 600px;\n  margin: 1rem auto 1.75rem;\n  font-size: 1rem;\n}\n\n.search-bar {\n  display: flex;\n  gap: .5rem;\n  max-width: 520px;\n  margin: 0 auto;\n}\n.search-bar input { flex: 1; }\n\n/* ── Form elements ─────────────────────────────────────────────────────────── */\ninput[type="search"],\ninput[type="text"],\nselect {\n  background: var(--card);\n  border: 1px solid var(--border);\n  color: var(--text);\n  border-radius: var(--radius-sm);\n  padding: .55rem .85rem;\n  font-size: .9rem;\n  outline: none;\n  transition: border-color var(--transition);\n  width: 100%;\n}\ninput[type="search"]:focus,\ninput[type="text"]:focus,\nselect:focus { border-color: var(--accent); }\nselect { cursor: pointer; }\n\nbutton, .btn {\n  display: inline-flex;\n  align-items: center;\n  background: var(--accent);\n  color: #0b0f14;\n  border: none;\n  border-radius: var(--radius-sm);\n  padding: .55rem 1.25rem;\n  font-size: .9rem;\n  font-weight: 600;\n  cursor: pointer;\n  transition: opacity var(--transition), background var(--transition);\n  white-space: nowrap;\n}\nbutton:hover, .btn:hover { opacity: .88; }\nbutton.secondary {\n  background: var(--border);\n  color: var(--text);\n}\n\n/* ── Stats row ─────────────────────────────────────────────────────────────── */\n\n\n/* ── Sources banner ────────────────────────────────────────────────────────── */\n.sources-note {\n  font-size: .75rem;\n  color: var(--muted);\n  margin-top: .5rem;\n  display: block;\n  text-align: center;\n}\n\n.sources-banner {\n  display: flex;\n  flex-wrap: wrap;\n  gap: .4rem;\n  align-items: center;\n  margin: 1.25rem 0 2.5rem;\n}\n.badge {\n  background: var(--card2);\n  border: 1px solid var(--border);\n  color: var(--muted);\n  font-size: .72rem;\n  padding: .2rem .55rem;\n  border-radius: 100px;\n}\n.sources-banner .note {\n  color: var(--muted);\n  font-size: .75rem;\n  margin-left: .25rem;\n}\n\n/* ── Sections ──────────────────────────────────────────────────────────────── */\n.section { margin-bottom: 3rem; }\n\n.section-header {\n  display: flex;\n  justify-content: space-between;\n  align-items: baseline;\n  margin-bottom: 1.1rem;\n}\n.section-header h2 { font-size: 1.2rem; font-weight: 700; }\n.see-all { font-size: .85rem; color: var(--accent); }\n\n/* ── Cards ─────────────────────────────────────────────────────────────────── */\n.card {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius);\n  padding: 1.1rem 1.25rem;\n  transition: border-color var(--transition);\n}\n.card:hover { border-color: rgba(61, 214, 140, .35); }\n.card a.card-link {\n  display: block;\n  color: inherit;\n  text-decoration: none;\n}\n\n.card-top {\n  display: flex;\n  justify-content: space-between;\n  align-items: flex-start;\n  gap: .75rem;\n  margin-bottom: .5rem;\n}\n.card-mfr { font-size: .72rem; text-transform: uppercase; letter-spacing: .08em; color: var(--muted); }\n.card-title { font-size: 1.05rem; font-weight: 600; margin: .2rem 0; }\n.card-codename { font-family: monospace; font-size: .82rem; color: var(--accent); }\n.card-sub { font-size: .82rem; color: var(--muted); margin-top: .4rem; }\n\n/* ── Device grid ───────────────────────────────────────────────────────────── */\n.device-grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));\n  gap: .85rem;\n}\n\n/* ── Skeleton loading ──────────────────────────────────────────────────────── */\n.skeleton {\n  background: linear-gradient(90deg, var(--card) 25%, var(--card2) 50%, var(--card) 75%);\n  background-size: 200% 100%;\n  animation: shimmer 1.5s infinite;\n  border-radius: var(--radius);\n  min-height: 120px;\n}\n.skeleton * { opacity: 0; }\n@keyframes shimmer {\n  0%   { background-position: 200% 0; }\n  100% { background-position: -200% 0; }\n}\n\n/* ── Filter bar ────────────────────────────────────────────────────────────── */\n.filter-bar {\n  display: flex;\n  flex-wrap: wrap;\n  gap: .6rem;\n  margin: 1.25rem 0;\n}\n.filter-bar input { flex: 1; min-width: 200px; }\n.filter-bar select { min-width: 140px; width: auto; }\n\n/* ── Results meta ──────────────────────────────────────────────────────────── */\n.results-meta { font-size: .82rem; color: var(--muted); margin-bottom: .75rem; }\n\n/* ── Page header ───────────────────────────────────────────────────────────── */\n.page-header { margin-bottom: 1.25rem; }\n.page-header h1 { font-size: 1.8rem; font-weight: 800; }\n.page-sub { color: var(--muted); margin-top: .4rem; font-size: .9rem; }\n.page-sub a { color: var(--accent); }\n\n/* ── Badges / chips ────────────────────────────────────────────────────────── */\n.chip {\n  display: inline-block;\n  font-size: .72rem;\n  padding: .18rem .55rem;\n  border-radius: 100px;\n  font-weight: 600;\n  border: 1px solid transparent;\n}\n.chip-green  { background: rgba(61,214,140,.12); color: var(--accent); border-color: rgba(61,214,140,.25); }\n.chip-blue   { background: rgba(96,165,250,.12); color: var(--info);   border-color: rgba(96,165,250,.25); }\n.chip-orange { background: rgba(251,191,36,.12); color: var(--warn);   border-color: rgba(251,191,36,.25); }\n.chip-red    { background: rgba(248,113,113,.12);color: var(--danger); border-color: rgba(248,113,113,.25); }\n.chip-gray   { background: var(--card2); color: var(--muted); border-color: var(--border); }\n\n/* ── Tags row ──────────────────────────────────────────────────────────────── */\n.tags { display: flex; flex-wrap: wrap; gap: .35rem; margin-top: .65rem; }\n\n/* ── Sources tags ──────────────────────────────────────────────────────────── */\n.source-tag { font-size: .7rem; color: var(--muted); font-family: monospace; }\n\n/* ── Detail page ───────────────────────────────────────────────────────────── */\n.breadcrumb { margin-bottom: 1.5rem; font-size: .85rem; color: var(--muted); }\n.breadcrumb a { color: var(--accent); }\n\n.detail-header {\n  border: 1px solid var(--border);\n  background: var(--card);\n  border-radius: var(--radius);\n  padding: 1.5rem;\n  margin-bottom: 1.5rem;\n}\n.detail-mfr { font-size: .75rem; text-transform: uppercase; letter-spacing: .1em; color: var(--muted); }\n.detail-title { font-size: 2rem; font-weight: 800; margin: .35rem 0; }\n.detail-codename { font-family: monospace; font-size: 1rem; color: var(--accent); }\n.detail-note {\n  margin-top: 1rem;\n  padding: .7rem 1rem;\n  background: rgba(251,191,36,.07);\n  border: 1px solid rgba(251,191,36,.2);\n  border-radius: var(--radius-sm);\n  font-size: .85rem;\n  color: rgba(251,191,36,.9);\n}\n\n.specs-grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));\n  gap: .5rem;\n  margin-top: 1.25rem;\n}\n.spec-item { display: flex; flex-direction: column; gap: .15rem; }\n.spec-key  { font-size: .72rem; text-transform: uppercase; letter-spacing: .06em; color: var(--muted); }\n.spec-val  { font-size: .88rem; }\n\n.section-title { font-size: 1.1rem; font-weight: 700; margin: 1.75rem 0 .85rem; }\n\n/* ── ROM list ──────────────────────────────────────────────────────────────── */\n.rom-list { display: flex; flex-direction: column; gap: .75rem; }\n.rom-card { background: var(--card); border: 1px solid var(--border); border-radius: var(--radius); padding: 1rem 1.25rem; }\n.rom-header { display: flex; flex-wrap: wrap; align-items: center; gap: .4rem; margin-bottom: .45rem; }\n.rom-name { font-weight: 700; font-size: 1.05rem; }\n.rom-meta { font-size: .82rem; color: var(--muted); display: flex; flex-wrap: wrap; gap: .75rem; }\n.rom-links { display: flex; flex-wrap: wrap; gap: .6rem; margin-top: .7rem; }\n.rom-link { font-size: .82rem; color: var(--accent); }\n.rom-note { font-size: .8rem; color: rgba(251,191,36,.8); margin-top: .5rem; border-left: 2px solid rgba(251,191,36,.3); padding-left: .6rem; }\n\n/* ── Recovery card ─────────────────────────────────────────────────────────── */\n.rec-card { background: var(--card); border: 1px solid var(--border); border-radius: var(--radius); padding: 1rem 1.25rem; }\n\n/* ── Tools ─────────────────────────────────────────────────────────────────── */\n.tools-section { margin-bottom: 2.5rem; }\n.tools-section h2 { font-size: 1rem; font-weight: 700; text-transform: uppercase; letter-spacing: .08em; color: var(--muted); margin-bottom: .85rem; }\n.tools-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: .85rem; }\n.tool-card { background: var(--card); border: 1px solid var(--border); border-radius: var(--radius); padding: 1.1rem 1.25rem; }\n.tool-header { display: flex; justify-content: space-between; align-items: flex-start; gap: .5rem; margin-bottom: .5rem; }\n.tool-name { font-weight: 700; font-size: 1rem; }\n.tool-desc { font-size: .83rem; color: var(--muted); margin-bottom: .75rem; }\n.tool-version { font-size: .78rem; font-family: monospace; color: var(--accent); }\n.tool-platform { font-size: .72rem; color: var(--muted); }\n.tool-links { display: flex; gap: .75rem; flex-wrap: wrap; margin-top: .65rem; }\n.tool-link { font-size: .82rem; }\n\n/* ── Android version table ─────────────────────────────────────────────────── */\n.table-wrap { overflow-x: auto; border-radius: var(--radius); border: 1px solid var(--border); margin-top: 1rem; }\ntable { width: 100%; border-collapse: collapse; font-size: .88rem; }\nthead { background: var(--card); }\nth { text-align: left; padding: .7rem 1rem; font-size: .75rem; text-transform: uppercase; letter-spacing: .07em; color: var(--muted); border-bottom: 1px solid var(--border); }\ntd { padding: .65rem 1rem; border-bottom: 1px solid var(--border); }\ntr:last-child td { border-bottom: none; }\ntr:hover td { background: var(--card2); }\n.loading-cell { text-align: center; color: var(--muted); padding: 2rem; }\n\n/* ── Pagination ────────────────────────────────────────────────────────────── */\n.pagination {\n  display: flex;\n  gap: .4rem;\n  justify-content: center;\n  margin-top: 2rem;\n  flex-wrap: wrap;\n}\n.page-btn {\n  background: var(--card);\n  border: 1px solid var(--border);\n  color: var(--text);\n  border-radius: var(--radius-sm);\n  padding: .35rem .75rem;\n  font-size: .82rem;\n  cursor: pointer;\n}\n.page-btn:hover { border-color: var(--accent); color: var(--accent); opacity: 1; }\n.page-btn.active { background: var(--accent); color: #0b0f14; border-color: var(--accent); }\n\n/* ── Version pills ─────────────────────────────────────────────────────────── */\n.version-pills { display: flex; flex-wrap: wrap; gap: .5rem; }\n.v-pill {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius);\n  padding: .5rem .9rem;\n  font-size: .82rem;\n  transition: border-color var(--transition);\n}\n.v-pill:hover { border-color: var(--accent); }\n.v-pill .v-num { font-weight: 700; color: var(--accent); }\n.v-pill .v-name { color: var(--muted); font-size: .75rem; }\n.pill { min-width: 80px; min-height: 48px; }\n\n/* ── ROM families cards ────────────────────────────────────────────────────── */\n.rom-families { display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: .75rem; }\n.rom-family-card { background: var(--card); border: 1px solid var(--border); border-radius: var(--radius); padding: 1rem 1.1rem; }\n.rom-family-name { font-weight: 700; font-size: .95rem; margin-bottom: .3rem; }\n.rom-family-count { font-size: .78rem; color: var(--muted); }\n\n/* ── Error / empty states ──────────────────────────────────────────────────── */\n.empty-state {\n  text-align: center;\n  padding: 3rem 1rem;\n  color: var(--muted);\n}\n.error-state {\n  background: rgba(248,113,113,.07);\n  border: 1px solid rgba(248,113,113,.2);\n  border-radius: var(--radius);\n  padding: 1rem 1.25rem;\n  color: var(--danger);\n  font-size: .88rem;\n}\n\n/* ── Footer ────────────────────────────────────────────────────────────────── */\n.site-footer {\n  border-top: 1px solid var(--border);\n  padding: 1.5rem 0;\n  font-size: .8rem;\n  color: var(--muted);\n  text-align: center;\n  margin-top: auto;\n}\n.footer-note { margin-top: .3rem; opacity: .7; }\n\n/* ── Scrollbar ─────────────────────────────────────────────────────────────── */\n::-webkit-scrollbar { width: 6px; height: 6px; }\n::-webkit-scrollbar-track { background: var(--bg); }\n::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }\n::-webkit-scrollbar-thumb:hover { background: rgba(61,214,140,.3); }\n\n/* ── Responsive ────────────────────────────────────────────────────────────── */\n@media (max-width: 640px) {\n  .header-inner { height: auto; padding: .75rem 0; }\n  nav { gap: .15rem; }\n  .nav-link { font-size: .78rem; padding: .3rem .45rem; }\n  .hero { padding: 2rem 0 1.25rem; }\n  /* Stats grid — 2 columns, last card centered */\n\n  .filter-bar { flex-direction: column; }\n  .filter-bar select { width: 100%; }\n  .detail-title { font-size: 1.5rem; }\n}\n\n\n.btn-github {\n  display: inline-flex;\n  align-items: center;\n  gap: .45rem;\n  background: var(--card2);\n  border: 1.5px solid var(--border);\n  color: var(--text);\n  padding: .55rem 1.2rem;\n  font-size: .9rem;\n  border-radius: var(--radius);\n  cursor: pointer;\n  text-decoration: none;\n  transition: border-color 180ms ease, color 180ms ease;\n}\n.btn-github:hover {\n  border-color: var(--accent);\n  color: var(--accent);\n}\n\n/* ── PWA Install button ──────────────────────────────────────────────────── */\n.btn-install {\n  background: transparent;\n  border: 1.5px solid var(--accent);\n  color: var(--accent);\n  padding: .55rem 1.4rem;\n  font-size: .9rem;\n  display: inline-flex;\n  align-items: center;\n  gap: .45rem;\n  border-radius: var(--radius);\n  cursor: pointer;\n  transition: background 180ms ease, color 180ms ease;\n}\n.btn-install:hover {\n  background: var(--accent);\n  color: #0b0f14;\n  opacity: 1;\n}\n\n/* ── Tablet (641px – 1024px) ──────────────────────────────────────────── */\n@media (max-width: 1024px) {\n  .container { padding: 0 1.25rem; }\n    .card-grid { grid-template-columns: repeat(2, 1fr); }\n}\n\n/* ── Mobile (max 640px) — extended ───────────────────────────────────── */\n@media (max-width: 640px) {\n  .card-grid { grid-template-columns: 1fr; }\n  .rom-card, .recovery-card, .tool-card { padding: .85rem 1rem; }\n  .detail-header { padding: 1.25rem 0; }\n  .detail-specs { grid-template-columns: 1fr; }\n  table { font-size: .82rem; }\n  th, td { padding: .5rem .6rem; }\n  .guide-header { flex-direction: column; align-items: flex-start; gap: .5rem; }\n  .type-tabs { gap: .3rem; }\n  .type-tab { font-size: .75rem; padding: .25rem .65rem; }\n  .page-header h1 { font-size: 1.5rem; }\n  .btn:not(.btn-github):not(.btn-install) { width: 100%; text-align: center; }\n}\n\n/* ── Very small screens (max 380px) ──────────────────────────────────── */\n@media (max-width: 380px) {\n  .logo { font-size: 1.1rem; }\n  .nav-link { font-size: .72rem; padding: .25rem .35rem; }\n\n}\n\n/* Improved placeholder contrast for accessibility */\ninput::placeholder,\nselect::placeholder,\ntextarea::placeholder {\n  color: #7a8fa8;\n  opacity: 1;\n}\n\n/* ── iOS Install Modal ────────────────────────────────────────────────────── */\n/* Hero action buttons never go full width */\n\n#ios-install-modal {\n  position: fixed;\n  inset: 0;\n  z-index: 1000;\n}\n\n.ios-modal-backdrop {\n  position: absolute;\n  inset: 0;\n  background: rgba(0,0,0,.55);\n  backdrop-filter: blur(2px);\n}\n\n.ios-modal-sheet {\n  position: absolute;\n  bottom: 0;\n  left: 0;\n  right: 0;\n  background: var(--card);\n  border-top: 1px solid var(--border);\n  border-radius: 1.25rem 1.25rem 0 0;\n  padding: 0 1.25rem 2rem;\n  transform: translateY(100%);\n  transition: transform 300ms cubic-bezier(.32,.72,0,1);\n  max-width: 480px;\n  margin: 0 auto;\n}\n\n.ios-modal-sheet.ios-modal-open {\n  transform: translateY(0);\n}\n\n.ios-modal-handle {\n  width: 36px;\n  height: 4px;\n  background: var(--border);\n  border-radius: 2px;\n  margin: .85rem auto 1.25rem;\n}\n\n.ios-modal-header {\n  display: flex;\n  align-items: center;\n  gap: .85rem;\n  margin-bottom: 1.5rem;\n}\n\n.ios-modal-icon {\n  width: 52px;\n  height: 52px;\n  border-radius: 12px;\n  flex-shrink: 0;\n}\n\n.ios-modal-title {\n  font-weight: 700;\n  font-size: 1.05rem;\n}\n\n.ios-modal-sub {\n  font-size: .8rem;\n  color: var(--muted);\n  margin-top: .2rem;\n}\n\n.ios-modal-close {\n  margin-left: auto;\n  background: var(--card2);\n  border: none;\n  color: var(--muted);\n  width: 28px;\n  height: 28px;\n  border-radius: 50%;\n  font-size: .85rem;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-shrink: 0;\n}\n\n.ios-modal-steps {\n  display: flex;\n  flex-direction: column;\n  gap: 0;\n  background: var(--card2);\n  border: 1px solid var(--border);\n  border-radius: var(--radius);\n  overflow: hidden;\n  margin-bottom: 1.25rem;\n}\n\n.ios-modal-divider {\n  height: 1px;\n  background: var(--border);\n}\n\n.ios-modal-step {\n  display: flex;\n  align-items: center;\n  gap: .85rem;\n  padding: .9rem 1rem;\n}\n\n.ios-step-num {\n  width: 26px;\n  height: 26px;\n  background: var(--accent);\n  color: #0b0f14;\n  border-radius: 50%;\n  font-weight: 700;\n  font-size: .8rem;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-shrink: 0;\n}\n\n.ios-step-content {\n  flex: 1;\n}\n\n.ios-step-title {\n  font-weight: 600;\n  font-size: .9rem;\n}\n\n.ios-step-desc {\n  font-size: .78rem;\n  color: var(--muted);\n  margin-top: .15rem;\n}\n\n.ios-step-icon {\n  color: var(--accent);\n  flex-shrink: 0;\n}\n\n.ios-modal-arrow {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: .4rem;\n  font-size: .8rem;\n  color: var(--muted);\n  animation: ios-bounce 1.5s ease-in-out infinite;\n}\n\n@keyframes ios-bounce {\n  0%, 100% { transform: translateY(0); }\n  50%       { transform: translateY(4px); }\n}\n\n/* ── Nav action buttons (Install + GitHub) in header ─────────────────────── */\n.nav-actions {\n  display: flex;\n  align-items: center;\n  gap: .5rem;\n  flex-shrink: 0;\n  /* On desktop: push to right end of header */\n}\n.btn-sm {\n  display: inline-flex;\n  align-items: center;\n  gap: .3rem;\n  padding: .4rem .85rem;\n  font-size: .82rem;\n  font-weight: 600;\n  border-radius: 8px;\n  white-space: nowrap;\n  cursor: pointer;\n  text-decoration: none;\n  transition: opacity 150ms;\n}\n.btn-sm:hover { opacity: .85; }\n.btn-sm svg { flex-shrink: 0; }\n#pwa-install-wrap {\n  display: none;           /* JS sets display:flex when installable */\n  align-items: center;\n  flex-shrink: 0;          /* never compress */\n  width: auto;             /* never stretch full-width */\n}\n\n/* Mobile: nav-actions sit in header row, compact */\n@media (max-width: 640px) {\n  .nav-actions {\n    gap: .3rem;\n    flex-direction: row !important;  /* MUST be row — never column */\n    flex-wrap: nowrap !important;\n    align-items: center;\n    order: 2;\n    flex-shrink: 0;\n  }\n  .header-inner {\n    flex-wrap: nowrap !important;   /* Prevent header from wrapping */\n  }\n  .nav-actions .btn-sm { padding:.35rem .55rem; font-size:.75rem; flex-shrink:0; }\n  #pwa-install-wrap { width:auto; flex-shrink:0; }\n  .btn-sm .btn-label { display:none; }\n}\n@media (min-width: 641px) {\n  .btn-sm .btn-label { display: inline; }\n}\n\n/* ── Hamburger menu ───────────────────────────────────────────────────────── */\n.nav-toggle {\n  display: none;\n  flex-direction: column;\n  gap: 5px;\n  background: none;\n  border: none;\n  cursor: pointer;\n  padding: .4rem;\n  margin-left: auto;\n}\n.nav-toggle span {\n  display: block;\n  width: 22px;\n  height: 2px;\n  background: var(--text);\n  border-radius: 2px;\n  transition: transform 200ms ease, opacity 200ms ease;\n}\n\n@media (max-width: 640px) {\n  .nav-toggle { display: flex; order: 3; }\n  .nav-actions { order: 2; }\n  .logo { order: 1; }\n\n  #main-nav {\n    display: none;\n    position: absolute;\n    top: 100%;\n    left: 0;\n    right: 0;\n    background: var(--card);\n    border-bottom: 1px solid var(--border);\n    padding: .5rem 1rem 1rem;\n    flex-direction: column;\n    gap: .1rem;\n    z-index: 200;\n  }\n  #main-nav.nav-open { display: flex; }\n  .nav-link { font-size: .95rem; padding: .6rem .5rem; }\n\n  /* Hamburger → X when open */\n  .nav-toggle[aria-expanded="true"] span:nth-child(1) {\n    transform: translateY(7px) rotate(45deg);\n  }\n  .nav-toggle[aria-expanded="true"] span:nth-child(2) {\n    opacity: 0;\n  }\n  .nav-toggle[aria-expanded="true"] span:nth-child(3) {\n    transform: translateY(-7px) rotate(-45deg);\n  }\n\n  .header-inner { position: relative; }\n}\n\n\n\n/* ── Scroll animations (IntersectionObserver pattern) ──────────────────────── */\n/* Reveal — only when JS running + user allows motion */\n@media (prefers-reduced-motion: no-preference) {\n  html.js-anim .reveal {\n    opacity: 0; transform: translateY(20px);\n    will-change: opacity, transform;\n    transition: opacity 550ms cubic-bezier(.22,1,.36,1), transform 550ms cubic-bezier(.22,1,.36,1);\n  }\n  html.js-anim .reveal.visible { opacity: 1; transform: none; }\n  html.js-anim .reveal-grid > * {\n    opacity: 0; transform: translateY(16px);\n    will-change: opacity, transform;\n    transition: opacity 480ms cubic-bezier(.22,1,.36,1), transform 480ms cubic-bezier(.22,1,.36,1);\n  }\n}\n\n\n/* ════════════════════════════════════════════════\n   WILD ANIMATIONS — Droidify motion system\n   ════════════════════════════════════════════════ */\n\n/* ── Number roll keyframes ─────────────────────── */\n@keyframes numRoll {\n  0%   { transform: translateY(100%); opacity: 0; }\n  10%  { opacity: 1; }\n  90%  { opacity: 1; }\n  100% { transform: translateY(0);    opacity: 1; }\n}\n@keyframes numRollOut {\n  from { transform: translateY(0);   opacity: 1; }\n  to   { transform: translateY(-80%); opacity: 0; }\n}\n@keyframes digitFlip {\n  0%   { transform: rotateX(-90deg) translateY(-50%); opacity: 0; }\n  100% { transform: rotateX(0deg)   translateY(0);    opacity: 1; }\n}\n\n/* ── Hero entrance ─────────────────────────────── */\n@keyframes heroSlideUp {\n  from { opacity: 0; transform: translateY(32px); }\n  to   { opacity: 1; transform: none; }\n}\n@keyframes pageEnter {\n  from { opacity: 0; transform: translateY(14px); }\n  to   { opacity: 1; transform: none; }\n}\n\n/* ── Card hover glow + lift ────────────────────── */\n.card {\n  transition: transform 240ms cubic-bezier(.34,1.2,.64,1),\n              border-color 200ms ease, box-shadow 240ms ease;\n}\n@media (prefers-reduced-motion: no-preference) {\n  html.js-anim .card:hover {\n    transform: translateY(-5px) scale(1.015);\n    border-color: var(--accent);\n    box-shadow: 0 12px 40px rgba(61,214,140,.15), 0 2px 8px rgba(61,214,140,.08);\n  }\n\n  /* ── Stat value slot-machine roll ─────────────── */\n  .stat-value.rolling {\n    display: inline-block;\n    overflow: hidden;\n    position: relative;\n  }\n  .stat-digit {\n    display: inline-block;\n    animation: numRoll 600ms cubic-bezier(.22,1,.36,1) forwards;\n  }\n\n  /* ── Badge pop on hover ───────────────────────── */\n  .badge, .chip {\n    transition: transform 150ms cubic-bezier(.34,1.56,.64,1),\n                background 180ms ease, color 180ms ease;\n  }\n  .badge:hover, .chip:hover {\n    transform: scale(1.12) translateY(-1px);\n    background: var(--accent);\n    color: #0b0f14;\n  }\n\n  /* ── Nav link sweep underline ─────────────────── */\n  .nav-link {\n    position: relative;\n  }\n  .nav-link::after {\n    content: \'\';\n    position: absolute;\n    bottom: -2px; left: 50%; right: 50%;\n    height: 2px;\n    background: var(--accent);\n    border-radius: 2px;\n    transition: left 220ms cubic-bezier(.22,1,.36,1),\n                right 220ms cubic-bezier(.22,1,.36,1);\n  }\n  .nav-link:hover::after, .nav-link.active::after {\n    left: 0; right: 0;\n  }\n\n  /* ── Search bar focus pulse ───────────────────── */\n  input[type="search"]:focus, input[type="text"]:focus {\n    box-shadow: 0 0 0 3px rgba(61,214,140,.2), 0 0 0 1px var(--accent);\n    border-color: var(--accent);\n    transition: box-shadow 200ms ease, border-color 200ms ease;\n  }\n\n  /* ── Button press ─────────────────────────────── */\n  .btn:active, .btn-sm:active, button:active {\n    transform: scale(0.96);\n    transition: transform 80ms ease;\n  }\n\n  /* ── Search button shimmer ────────────────────── */\n  #search-btn, .btn-primary {\n    position: relative;\n    overflow: hidden;\n  }\n  #search-btn::before, .btn-primary::before {\n    content: \'\';\n    position: absolute;\n    top: 0; left: -100%;\n    width: 60%;\n    height: 100%;\n    background: linear-gradient(90deg, transparent, rgba(255,255,255,.18), transparent);\n    animation: btnShimmer 2.4s ease-in-out infinite;\n  }\n  @keyframes btnShimmer {\n    0%   { left: -100%; }\n    50%  { left: 150%; }\n    100% { left: 150%; }\n  }\n\n  /* ── Version pill lift ────────────────────────── */\n  .v-pill {\n    transition: transform 220ms cubic-bezier(.34,1.56,.64,1),\n                background 180ms ease, border-color 180ms ease;\n  }\n  .v-pill:hover {\n    transform: translateY(-4px) scale(1.04);\n    background: var(--card2);\n    border-color: var(--accent);\n  }\n\n  /* ── ROM family card tilt on hover ───────────── */\n  .rom-family-card {\n    transition: transform 260ms cubic-bezier(.34,1.3,.64,1),\n                border-color 200ms ease, box-shadow 260ms ease;\n  }\n  .rom-family-card:hover {\n    transform: translateY(-4px) rotate(0.4deg);\n    border-color: var(--accent);\n    box-shadow: 0 8px 28px rgba(61,214,140,.12);\n  }\n\n  /* ── Source badge bounce in (staggered) ──────── */\n  .sources-banner .badge {\n    opacity: 0;\n    transform: scale(0.7) translateY(8px);\n    animation: badgePop 400ms cubic-bezier(.34,1.56,.64,1) forwards;\n  }\n  @keyframes badgePop {\n    to { opacity:1; transform:scale(1) translateY(0); }\n  }\n  .sources-banner.visible .badge:nth-child(1)  { animation-delay:0ms; }\n  .sources-banner.visible .badge:nth-child(2)  { animation-delay:40ms; }\n  .sources-banner.visible .badge:nth-child(3)  { animation-delay:80ms; }\n  .sources-banner.visible .badge:nth-child(4)  { animation-delay:120ms; }\n  .sources-banner.visible .badge:nth-child(5)  { animation-delay:160ms; }\n  .sources-banner.visible .badge:nth-child(6)  { animation-delay:200ms; }\n  .sources-banner.visible .badge:nth-child(7)  { animation-delay:240ms; }\n  .sources-banner.visible .badge:nth-child(8)  { animation-delay:280ms; }\n  .sources-banner.visible .badge:nth-child(9)  { animation-delay:320ms; }\n  .sources-banner.visible .badge:nth-child(10) { animation-delay:360ms; }\n  .sources-banner.visible .badge:nth-child(11) { animation-delay:400ms; }\n\n  /* ── Logo brand flicker ───────────────────────── */\n  .logo:hover .accent {\n    animation: accentFlicker 500ms ease;\n  }\n  @keyframes accentFlicker {\n    0%,100% { opacity:1; }\n    25%     { opacity:.6; }\n    50%     { opacity:1; }\n    75%     { opacity:.8; }\n  }\n\n  /* ── Stat box entrance ────────────────────────── */\n  html.js-anim .stats-box {\n    animation: statsSlideIn 600ms cubic-bezier(.22,1,.36,1) 300ms forwards;\n    opacity: 0;\n    transform: translateY(12px);\n  }\n  @keyframes statsSlideIn {\n    to { opacity:1; transform:none; }\n  }\n\n  /* ── Page transition fade ─────────────────────── */\n  html.js-anim main.container {\n    animation: pageEnter 380ms cubic-bezier(.22,1,.36,1) forwards;\n  }\n\n  /* ── Skeleton shimmer improvement ───────────────  */\n  @keyframes shimmer {\n    0%   { background-position: -600px 0; }\n    100% { background-position:  600px 0; }\n  }\n  .skeleton {\n    background-size: 600px 100% !important;\n    animation: shimmer 1.6s ease-in-out infinite !important;\n  }\n\n  /* cardEntrance removed — cardSpring handles stagger */\n\n  /* ── Section header typewriter cursor blink ─────  */\n  .section-header h2::after {\n    content: \'_\';\n    color: var(--accent);\n    animation: cursorBlink 1s step-end infinite;\n    margin-left: 2px;\n  }\n  @keyframes cursorBlink { 0%,100% { opacity:1; } 50% { opacity:0; } }\n\n  /* ── Scroll-triggered counter pipeline ─────────  */\n  .stat-value[data-rolling="true"] {\n    clip-path: inset(0);\n  }\n}\n\n\n/* ════════════════════════════════════════════════════\n   DEEP ANIMATION SYSTEM v2\n   Research sources: MDN, CSS-Tricks, Prismic, Smashing\n   All animations: GPU-composited (transform + opacity only)\n   Respects prefers-reduced-motion throughout\n   ════════════════════════════════════════════════════ */\n\n/* ── 1. @property — animatable CSS custom properties ──\n   Enables smooth gradient color transitions natively.\n   Source: MDN @property, CSS-Tricks animation almanac  */\n@property --grad-angle {\n  syntax: \'<angle>\';\n  inherits: false;\n  initial-value: 135deg;\n}\n@property --glow-opacity {\n  syntax: \'<number>\';\n  inherits: false;\n  initial-value: 0;\n}\n\n/* ── 2. Animated gradient border on cards (hover) ──── */\n@media (prefers-reduced-motion: no-preference) {\n  .card {\n    position: relative;\n    isolation: isolate;\n  }\n  .card::before {\n    content: \'\';\n    position: absolute;\n    inset: -1px;\n    border-radius: inherit;\n    background: conic-gradient(\n      from var(--grad-angle),\n      transparent 0%,\n      var(--accent) 20%,\n      transparent 40%\n    );\n    opacity: 0;\n    z-index: -1;\n    transition: opacity 300ms ease;\n    --grad-angle: 0deg;\n    animation: none;\n  }\n  .card:hover::before {\n    opacity: 0.6;\n    animation: gradRotate 2s linear infinite;\n  }\n  @keyframes gradRotate {\n    to { --grad-angle: 360deg; }\n  }\n\n  /* ── 3. Neon glow pulse on accent elements ─────────\n     Double box-shadow creates depth, alternates intensity  */\n  .btn-install {\n    animation: neonPulse 2.5s ease-in-out infinite;\n  }\n  @keyframes neonPulse {\n    0%, 100% {\n      box-shadow:\n        0 0 4px rgba(61,214,140,.3),\n        0 0 12px rgba(61,214,140,.1);\n    }\n    50% {\n      box-shadow:\n        0 0 8px rgba(61,214,140,.6),\n        0 0 24px rgba(61,214,140,.25),\n        0 0 48px rgba(61,214,140,.08);\n    }\n  }\n\n  /* ── 4. Floating particles on hero background ───────\n     Pure CSS, no JS. Uses nth-child for variety.        */\n  .hero {\n    position: relative;\n    overflow: hidden;\n  }\n  .hero::before,\n  .hero::after {\n    content: \'\';\n    position: absolute;\n    width: 2px;\n    height: 2px;\n    background: var(--accent);\n    border-radius: 50%;\n    opacity: 0;\n    animation: heroParticle 6s ease-in-out infinite;\n  }\n  .hero::before {\n    top: 30%;\n    left: 15%;\n    animation-delay: 0s;\n    animation-duration: 7s;\n  }\n  .hero::after {\n    top: 60%;\n    left: 80%;\n    animation-delay: 2.5s;\n    animation-duration: 5s;\n    width: 3px;\n    height: 3px;\n  }\n  @keyframes heroParticle {\n    0%   { opacity: 0;   transform: translateY(0)    scale(1); }\n    20%  { opacity: 0.8; }\n    80%  { opacity: 0.4; }\n    100% { opacity: 0;   transform: translateY(-60px) scale(2); }\n  }\n\n  /* ── 5. Text shimmer on hero headline ───────────────\n     Gradient sweep across text using background-clip    */\n  .hero h1 {\n    background: linear-gradient(\n      90deg,\n      var(--text) 0%,\n      var(--text) 40%,\n      rgba(61,214,140,.9) 50%,\n      var(--text) 60%,\n      var(--text) 100%\n    );\n    background-size: 200% auto;\n    -webkit-background-clip: text;\n    background-clip: text;\n    -webkit-text-fill-color: transparent;\n    animation: textShimmer 5s linear infinite;\n    animation-delay: 1s;\n  }\n  @keyframes textShimmer {\n    0%   { background-position: -200% center; }\n    100% { background-position:  200% center; }\n  }\n\n  /* ── 6. Scroll-driven reveal (native CSS, no JS) ────\n     Uses animation-timeline: view() — Chrome/Edge 115+\n     Falls back to JS-based reveal on other browsers     */\n  @supports (animation-timeline: view()) {\n    .reveal {\n      opacity: 0;\n      transform: translateY(20px);\n      animation: revealNative linear forwards;\n      animation-timeline: view();\n      animation-range: entry 0% entry 40%;\n    }\n    .reveal.visible {\n      /* JS added .visible — ensure it stays visible */\n      opacity: 1;\n      transform: none;\n    }\n    .reveal-grid > * {\n      opacity: 0;\n      transform: translateY(16px);\n      animation: revealNative linear forwards;\n      animation-timeline: view();\n      animation-range: entry 0% entry 50%;\n    }\n    @keyframes revealNative {\n      from { opacity: 0; transform: translateY(20px); }\n      to   { opacity: 1; transform: none; }\n    }\n  }\n\n  /* ── 7. Scanline overlay on stat box ────────────────\n     Subtle CRT scanline effect, very low opacity        */\n  .stats-box::after {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background: repeating-linear-gradient(\n      0deg,\n      transparent,\n      transparent 2px,\n      rgba(0,0,0,.04) 2px,\n      rgba(0,0,0,.04) 4px\n    );\n    pointer-events: none;\n    border-radius: inherit;\n    opacity: 0;\n    transition: opacity 400ms ease;\n  }\n  .stats-box:hover::after {\n    opacity: 1;\n  }\n\n  /* ── 8. Morphing border-radius on logo ──────────────\n     Organic shape-shift on hover                       */\n  .logo:hover .accent {\n    animation: logoPulse 600ms ease, morphText 2s ease-in-out infinite 600ms;\n  }\n  @keyframes morphText {\n    0%, 100% { letter-spacing: -.04em; }\n    50%       { letter-spacing: .02em; }\n  }\n\n  /* ── 9. Spring-style card entrance (stagger cascade) */\n  @keyframes cardSpring {\n    0%   { opacity: 0; transform: translateY(30px) scale(0.94); }\n    60%  { opacity: 1; transform: translateY(-4px)  scale(1.01); }\n    80%  { transform: translateY(2px) scale(0.995); }\n    100% { transform: none; }\n  }\n  html.js-anim .reveal-grid.visible > *:nth-child(1)\n    { animation: cardSpring 520ms cubic-bezier(.22,1,.36,1) 0ms   forwards; opacity: 0; }\n  html.js-anim .reveal-grid.visible > *:nth-child(2)\n    { animation: cardSpring 520ms cubic-bezier(.22,1,.36,1) 65ms  forwards; opacity: 0; }\n  html.js-anim .reveal-grid.visible > *:nth-child(3)\n    { animation: cardSpring 520ms cubic-bezier(.22,1,.36,1) 130ms forwards; opacity: 0; }\n  html.js-anim .reveal-grid.visible > *:nth-child(4)\n    { animation: cardSpring 520ms cubic-bezier(.22,1,.36,1) 195ms forwards; opacity: 0; }\n  html.js-anim .reveal-grid.visible > *:nth-child(5)\n    { animation: cardSpring 520ms cubic-bezier(.22,1,.36,1) 260ms forwards; opacity: 0; }\n  html.js-anim .reveal-grid.visible > *:nth-child(6)\n    { animation: cardSpring 520ms cubic-bezier(.22,1,.36,1) 325ms forwards; opacity: 0; }\n\n  /* ── 10. Stat value glint on load ───────────────────\n     One-shot light streak across each stat number       */\n  .stat-value {\n    position: relative;\n    overflow: hidden;\n  }\n  .stat-value::after {\n    content: \'\';\n    position: absolute;\n    top: 0;\n    left: -100%;\n    width: 60%;\n    height: 100%;\n    background: linear-gradient(\n      90deg,\n      transparent,\n      rgba(255,255,255,.22),\n      transparent\n    );\n    animation: statGlint 2.5s ease 1.8s forwards;\n  }\n  @keyframes statGlint {\n    0%   { left: -100%; opacity: 0; }\n    10%  { opacity: 1; }\n    100% { left: 160%;  opacity: 0; }\n  }\n\n  /* ── 11. Nav underline draw animation (SVG-style) ───\n     Underline expands from center outward              */\n  .nav-link.active::after {\n    animation: underlineDraw 300ms cubic-bezier(.22,1,.36,1) forwards;\n  }\n  @keyframes underlineDraw {\n    from { left: 50%; right: 50%; }\n    to   { left: 0;   right: 0; }\n  }\n\n  /* ── 12. Ghost shimmer on skeleton elements ─────────\n     Multi-stop gradient sweep — more realistic         */\n  @keyframes skeletonWave {\n    0%   { background-position: -400px 0; }\n    100% { background-position:  400px 0; }\n  }\n  .skeleton {\n    background-image: linear-gradient(\n      90deg,\n      var(--card2) 0px,\n      rgba(255,255,255,.04) 40px,\n      var(--card2) 80px\n    ) !important;\n    background-size: 400px 100% !important;\n    animation: skeletonWave 1.4s ease-in-out infinite !important;\n  }\n\n  /* ── 13. Chip/badge entrance with spring bounce ─────  */\n  .sources-banner.visible .badge {\n    animation: badgeSpring 450ms cubic-bezier(.34,1.56,.64,1) forwards;\n    opacity: 0;\n  }\n  @keyframes badgeSpring {\n    from { opacity: 0; transform: scale(0.6) translateY(8px); }\n    to   { opacity: 1; transform: scale(1)   translateY(0); }\n  }\n\n  /* ── 14. Focus-within glow on search area ───────────  */\n  .search-bar:focus-within {\n    animation: searchGlow 300ms ease forwards;\n  }\n  @keyframes searchGlow {\n    to {\n      box-shadow: 0 0 0 3px rgba(61,214,140,.2),\n                  0 4px 20px rgba(61,214,140,.08);\n    }\n  }\n\n  /* ── 15. Loading bar progress animation ─────────────\n     Terminal-style indeterminate progress bar          */\n  .ls-bar {\n    position: relative;\n    overflow: hidden;\n  }\n  .ls-bar::after {\n    content: \'\';\n    position: absolute;\n    top: 0;\n    left: 0;\n    right: 0;\n    bottom: 0;\n    background: linear-gradient(\n      90deg,\n      transparent 0%,\n      rgba(255,255,255,.4) 50%,\n      transparent 100%\n    );\n    animation: barSheen 1s ease-in-out infinite;\n    animation-delay: 0.5s;\n  }\n  @keyframes barSheen {\n    from { transform: translateX(-100%); }\n    to   { transform: translateX(200%); }\n  }\n}\n\n/* ── Always-on: smooth transition on interactive elements ── */\n.btn-install, .btn-github {\n  transition:\n    transform 150ms cubic-bezier(.34,1.2,.64,1),\n    box-shadow 200ms ease,\n    background 180ms ease,\n    color 180ms ease,\n    border-color 180ms ease;\n}\n.btn-install:hover { transform: translateY(-2px) scale(1.03); }\n.btn-github:hover  { transform: translateY(-2px); }\n.btn-install:active, .btn-github:active {\n  transform: scale(0.96) translateY(0);\n  transition-duration: 80ms;\n}\n'
